sql:
SELECT measurement_id, product_category, size, body_length
FROM size_measurements
WHERE brand_id = 1;

SELECT brand_id, COUNT(style_id) AS number_of_styles
FROM styles
GROUP BY brand_id;

SELECT style_id
FROM size_measurements
WHERE brand_id = 1 AND style_id = 1 AND size = 'S';

SELECT AVG(body_length) AS average_body_length
FROM size_measurements
WHERE brand_id = 1 AND style_id = 1;

SELECT s.style_name, b.brand_name
FROM styles s
JOIN brands b ON s.brand_id = b.brand_id;

SELECT AVG(size_measurements.body_length) AS average_body_length
FROM size_measurements
WHERE size_measurements.style_id = 1 AND size_measurements.brand_id IN (1, 0);

